function CommonGrid() {
    return (<div>
        <StackGrid
            appear={scaleDown.appear}
            appeared={scaleDown.appeared}
            enter={scaleDown.enter}
            entered={scaleDown.entered}
            leaved={scaleDown.leaved}

        >
            <div key="key1">Things</div>
            <div key="key2">are</div>
            <div key="key3">under</div>
            <div key="key4">development</div>
        </StackGrid>
    </div>)
}

function PortfolioMobile(props) {
    return (
        <Accordion className="portfolio-mobile" defaultActiveKey="0">
            <Accordion.Item eventKey="0">
                <Accordion.Header>Products/Services (1)</Accordion.Header>
                <Accordion.Body>
                    <PortfolioItem vp={props} />
                </Accordion.Body>
            </Accordion.Item>
            <Accordion.Item eventKey="1">
                <Accordion.Header>Music (0)</Accordion.Header>
                <Accordion.Body>
                    No records found!
                </Accordion.Body>
            </Accordion.Item>
            <Accordion.Item eventKey="2">
                <Accordion.Header>Art (0)</Accordion.Header>
                <Accordion.Body>
                    No records found!
                </Accordion.Body>
            </Accordion.Item>
            <Accordion.Item eventKey="3">
                <Accordion.Header>Papers (0)</Accordion.Header>
                <Accordion.Body>
                    No records found!
                </Accordion.Body>
            </Accordion.Item>
        </Accordion>
    );
}

function Portfolio(props) {
    return (
        <>
            <Helmet>
                <title>Rajkishor | Portfolio</title>
            </Helmet>

            {props.vp === "m" && <>

                {/* <PortfolioMobile vp={props.vp}> </PortfolioMobile> */}
                <CommonGrid />

            </>}

            {props.vp !== "m" && <>

                <div className='Portfolio'>

                    {/* <TabMaker vp={props.vp} /> */}

                    <CommonGrid />


                </div>

            </>}

        </>

    );
}

export default Portfolio;