import React from 'react';
import '../assets/css/About.scss';
import { Helmet } from 'react-helmet';
import Raj from '../assets/image/r.jpeg';

import { FaPhone, FaMailchimp } from 'react-icons/fa';





function About(props) {
 
    return (
        <>


            {
                props.vp === "t" &&
                <>
                    <img src={Raj} className='profile-pc-t' />

                </>
            }


            <Helmet>
                <title>Rajkishor | About </title>
            </Helmet>
            <div className={props.vp === "m" ? 'blog-wrapper-m' : 'blog-wrapper'}>
                {
                    props.vp === "m" &&
                    <>
                        <div>
                            <img src={Raj} className='profile-pc-m' />
                            <div className='phone-header'>
                                <p>Rajkishor Maharana</p>


                                <div className='phone headline'>
                                    +91 - 7683922389 {'\u00A0'} <FaPhone />
                                </div>
                                <div className='clear-line' />
                                <div className='email headline'>
                                    mrajkishor331@gmail.com{'\u00A0'}<FaMailchimp />
                                </div>
                                <div className='clear-line' />
                            </div>


                        </div>

                    </>
                }
                <h4>About Raj</h4>
                <h6>
                   Maverick, Nerd, Introverted..
                </h6>
                <br />
                <div className={props.vp === "m" ? 'mobile-wrapper' : ''}>

                    <h5>Profession</h5>
                    <h6>Software Engineer</h6>
             
                    <p><span className='def'>Platforms</span>: Full stack Web and Mobile, Big data, AI/ML, Distributed systems, Open source</p>      

                    <h5>Interests</h5>
                    <h6><p>DAW</p>/<p>Flamenco Guitar</p>/<p>Piano/Keyboard</p>/<p>PC Games</p>/<p>Vector/digital arts</p>/<p>Independent research</p>/<p>Startups</p></h6>


                    <br />
                    <h5>Academics</h5>
                    <h6>Government College of Engineering Kalahandi, Odisha, India</h6>
                    <p>BTech - 2016</p>

          
                </div>


                {
                    props.vp === "t" &&
                    <>
                        <hr />
                        <div className='contact-t'>
                            <div className='phone headline'>
                                +91 - 7683922389 {'\u00A0'} <FaPhone />
                            </div>
                            <div className='clear-line' />
                            <div className='email headline'>
                                mrajkishor331@gmail.com{'\u00A0'}<FaMailchimp />
                            </div>
                            <div className='clear-line' />
                        </div>


                    </>
                }



            </div>
        </>


    );
}

export default About;